options.css:
:host {
  --bg: #0b1118;
  --panel: rgba(13, 20, 29, 0.96);
  --panel-2: rgba(18, 29, 42, 0.94);
  --header: rgba(7, 13, 20, 0.88);
  --line: rgba(148, 163, 184, 0.18);
  --line-strong: rgba(148, 163, 184, 0.28);
  --muted: #91a1b5;
  --text: #e5edf6;
  --green: #10ac49;
  --yellow: #facc15;
  --orange: #fb923c;
  --red: #ef4444;
  --blue: #38bdf8;
  --violet: #a78bfa;
}

* { box-sizing: border-box; }

.sw48-root {
  width: 100%;
  min-height: 100%;
  padding: 16px;
  color: var(--text);
  font-family: Inter, Roboto, Arial, sans-serif;
  background:
    radial-gradient(circle at top left, rgba(34, 197, 94, 0.12), transparent 26%),
    radial-gradient(circle at top right, rgba(56, 189, 248, 0.10), transparent 30%),
    linear-gradient(135deg, #110d1d 0%, #102223 56%, #081815 100%);
}


.dash-header {
  display: flex;
  justify-content: space-between;
  gap: 18px;
  align-items: center;
  margin-bottom: 14px;
}

.brand-block {
  display: flex;
  align-items: center;
  gap: 14px;
  min-width: 0;
}

.logo-mark {
  width: 54px;
  height: 54px;
  border: 1px solid rgba(255, 255, 255, 0.18);
  border-radius: 14px;
  display: grid;
  place-items: center;
  color: #ffffff;
  font-weight: 900;
  letter-spacing: 0.04em;
  background: linear-gradient(135deg, rgba(34, 197, 94, 0.85), rgba(56, 189, 248, 0.65));
  box-shadow: 0 16px 34px rgba(0, 0, 0, 0.26);
}

.eyebrow {
  color: var(--blue);
  text-transform: uppercase;
  font-size: 11px;
  letter-spacing: 0.14em;
  margin-bottom: 3px;
}

h2, h3, p { margin: 0; }

h2 {
  font-size: 23px;
  line-height: 1.15;
  font-weight: 750;
}

.dash-header p,
.table-title-row p,
.debug-card p {
  color: var(--muted);
  margin-top: 4px;
  font-size: 12px;
}

.header-actions {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 9px;
}

.updated {
  color: var(--muted);
  font-size: 12px;
  white-space: nowrap;
}

.legend {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 10px;
  color: var(--muted);
  font-size: 12px;
}

.dot {
  width: 9px;
  height: 9px;
  display: inline-block;
  border-radius: 999px;
  margin-right: 6px;
  box-shadow: 0 0 12px currentColor;
}

.dot.up { color: var(--green); background: var(--green); }
.dot.warn { color: var(--orange); background: var(--orange); }
.dot.down { color: var(--red); background: var(--red); }
.dot.unknown { color: #64748b; background: #64748b; }

.kpi-grid {
  display: grid;
  grid-template-columns: repeat(5, minmax(0, 1fr));
  gap: 10px;
  margin-bottom: 12px;
}

.kpi-card {
  background: linear-gradient(180deg, rgba(18, 29, 42, 0.96), rgba(11, 17, 24, 0.94));
  border: 1px solid var(--line);
  border-radius: 12px;
  padding: 12px 14px;
  min-height: 82px;
  box-shadow: 0 12px 28px rgba(39, 79, 105, 0.18);
  position: relative;
  overflow: hidden;
}

.kpi-card::after {
  content: "";
  position: absolute;
  inset: auto 0 0 0;
  height: 4px;
  background: linear-gradient(90deg, rgba(56, 189, 248, 0.1), rgba(56, 189, 248, 0.75));
}

.kpi-card.good::after { background: linear-gradient(90deg, rgba(34, 197, 94, 0.12), rgba(34, 197, 94, 0.82)); }
.kpi-card.bad::after { background: linear-gradient(90deg, rgba(239, 68, 68, 0.12), rgba(239, 68, 68, 0.82)); }
.kpi-card.warn::after { background: linear-gradient(90deg, rgba(251, 146, 60, 0.12), rgba(251, 146, 60, 0.82)); }
.kpi-card.usage::after { background: linear-gradient(90deg, rgba(167, 139, 250, 0.12), rgba(167, 139, 250, 0.82)); }

.kpi-card span {
  color: var(--muted);
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.kpi-card strong {
  display: block;
  margin-top: 6px;
  font-size: 26px;
  line-height: 1;
}

.kpi-card small {
  display: block;
  color: var(--muted);
  margin-top: 8px;
  font-size: 11px;
}

.toolbar {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: center;
  padding: 10px;
  border: 1px solid var(--line);
  border-radius: 12px;
  background: rgba(26, 73, 73, 0.6);
  margin-bottom: 12px;
}

.search-box {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--muted);
  font-size: 12px;
  min-width: 300px;
}

.search-box input {
  width: 100%;
  color: var(--text);
  background: rgba(8, 26, 9, 0.9);
  border: 1px solid var(--line);
  border-radius: 9px;
  padding: 8px 10px;
  outline: none;
}

.search-box input:focus {
  border-color: rgba(20, 56, 71, 0.65);
  box-shadow: 0 0 0 2px rgba(184, 248, 56, 0.12);
}

.filter-box {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 7px;
}

.filter-chip {
  appearance: none;
  color: var(--muted);
  background: rgba(20, 77, 43, 0.9);
  border: 1px solid var(--line);
  border-radius: 999px;
  padding: 7px 11px;
  font-size: 12px;
  cursor: pointer;
}

.filter-chip.active,
.filter-chip:hover {
  color: #fff;
  border-color: rgba(22, 178, 245, 0.45);
  background: rgba(229, 243, 249, 0.14);
}

.table-card,
.debug-card {
  border: 1px solid var(--line);
  border-radius: 14px;
  background: rgba(10, 16, 24, 0.92);
  overflow: hidden;
  box-shadow: 0 18px 38px rgba(0, 0, 0, 0.26);
}

.table-title-row {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: center;
  padding: 13px 15px;
  background: linear-gradient(180deg, rgba(9, 7, 33, 0.96), rgba(13, 20, 29, 0.96));
  border-bottom: 1px solid var(--line);
}

.table-title-row h3 {
  font-size: 15px;
  font-weight: 700;
}

.table-title-row strong {
  color: #0da982;
}

.row-count {
  color: var(--muted);
  font-size: 12px;
  white-space: nowrap;
}

.table-scroll {
  width: 100%;
  overflow: auto;
  max-height: 200vh;
}

.port-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  min-width: 1320px;
}

.port-table thead th {
  position: sticky;
  top: 0;
  z-index: 2;
  color: #c8d5e5;
  background: #111827;
  border-bottom: 1px solid var(--line-strong);
  border-right: 1px solid rgba(215, 132, 90, 0.08);
  padding: 10px 12px;
  text-align: left;
  font-size: 12px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.045em;
  white-space: nowrap;
  cursor: pointer;
  user-select: none;
}

.port-table thead th:hover {
  color: #fff;
  background: #0a296c;
}

.port-table tbody td {
  border-bottom: 1px solid rgba(148, 163, 184, 0.10);
  border-right: 1px solid rgba(148, 163, 184, 0.06);
  padding: 8px 12px;
  vertical-align: middle;
  font-size: 13px;
  white-space: nowrap;
}

.port-table tbody tr {
  background: rgba(20, 30, 42, 0.92);
}

.port-table tbody tr:nth-child(even) {
  background: rgba(15, 23, 36, 0.92);
}

.port-table tbody tr:hover {
  background: rgba(29, 71, 67, 0.86);
}

.port-cell-main {
  font-weight: 800;
  color: #c0e4ff;
  min-width: 110px;
}

.subtext {
  display: block;
  color: var(--muted);
  font-size: 11px;
  margin-top: 2px;
}

.status-cell,
.usage-cell,
.counter-cell {
  min-width: 92px;
  text-align: center !important;
  font-weight: 800;
  color: #fff;
  text-shadow: 0 1px 0 rgba(0,0,0,0.2);
}

.status-cell.up,
.usage-cell.good,
.counter-cell.ok {
  background: linear-gradient(90deg, rgba(2, 61, 77, 0.88), rgba(15, 255, 155, 0.54));
}

.status-cell.down,
.usage-cell.bad,
.counter-cell.bad {
  background: linear-gradient(90deg, rgba(127, 29, 29, 0.94), rgba(239, 68, 68, 0.70));
}

.status-cell.warn,
.usage-cell.warn,
.counter-cell.warn {
  background: linear-gradient(90deg, rgba(194, 65, 12, 0.92), rgba(251, 146, 60, 0.65));
}

.status-cell.unknown,
.usage-cell.unknown,
.counter-cell.unknown {
  color: #cbd5e1;
  background: linear-gradient(90deg, rgba(51, 65, 85, 0.82), rgba(71, 85, 105, 0.50));
}

.traffic-cell {
  min-width: 180px;
}

.traffic-value {
  display: flex;
  justify-content: space-between;
  gap: 10px;
  align-items: baseline;
  margin-bottom: 5px;
}

.traffic-value strong {
  font-size: 13px;
  color: #f8fafc;
}

.traffic-value span {
  color: var(--muted);
  font-size: 11px;
}

.meter {
  height: 10px;
  background: rgba(15, 23, 42, 0.92);
  border: 1px solid rgba(148, 163, 184, 0.13);
  border-radius: 999px;
  overflow: hidden;
}

.meter > i {
  display: block;
  height: 100%;
  width: 0;
  border-radius: inherit;
}

.meter > i.download {
  background: linear-gradient(90deg, rgba(181, 198, 188, 0.95), rgba(56,189,248,0.95));
}

.meter > i.upload {
  background: linear-gradient(90deg, rgba(109, 71, 224, 0.95), rgba(251,146,60,0.95));
}

.speed-cell {
  min-width: 110px;
  font-weight: 700;
  color: #eaf2fb;
}

.type-cell {
  min-width: 160px;
  color: #cbd5e1;
}

.debug-card {
  margin-top: 12px;
  padding: 12px 14px;
}

.debug-card summary {
  cursor: pointer;
  color: #dbeafe;
  font-weight: 700;
}

.debug-card pre {
  max-height: 220px;
  overflow: auto;
  padding: 10px;
  border-radius: 10px;
  background: rgba(2, 6, 23, 0.88);
  color: #cbd5e1;
  font-size: 11px;
  white-space: pre-wrap;
  border: 1px solid rgba(148, 163, 184, 0.12);
}

.empty-state {
  display: none;
  flex-direction: column;
  gap: 6px;
  align-items: center;
  justify-content: center;
  margin-top: 12px;
  min-height: 120px;
  padding: 24px;
  color: var(--muted);
  background: rgba(15, 23, 42, 0.72);
  border: 1px dashed rgba(148, 163, 184, 0.28);
  border-radius: 14px;
  text-align: center;
}

.empty-state strong { color: #f8fafc; }

@media (max-width: 1000px) {
  .dash-header, .toolbar, .table-title-row {
    flex-direction: column;
    align-items: stretch;
  }
  .header-actions { align-items: flex-start; }
  .kpi-grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }
  .search-box { min-width: 0; }
}

@media (max-width: 860px) {
  .kpi-grid { grid-template-columns: 1fr; }
  .logo-mark { width: 46px; height: 46px; }
  h2 { font-size: 19px; }
}

.kpi-card.switch-status.good::after,
.kpi-card.switch-status.online::after {
  background: linear-gradient(90deg, rgba(34, 197, 94, 0.12), rgba(154, 154, 154, 0.82));
}

.kpi-card.switch-status.bad::after,
.kpi-card.switch-status.offline::after {
  background: linear-gradient(90deg, rgba(239, 68, 68, 0.12), rgba(239, 68, 68, 0.82));
}

.kpi-card.switch-status.unknown::after {
  background: linear-gradient(90deg, rgba(100, 116, 139, 0.12), rgba(100, 116, 139, 0.82));
}

.kpi-card.switch-status.online strong {
  color: var(--green);
}

.kpi-card.switch-status.offline strong {
  color: var(--red);
}

.kpi-card.switch-status.unknown strong {
  color: #94a3b8;
}

.host-cell-main {
  font-weight: 800;
  color: #eef6ff;
  min-width: 210px;
  max-width: 320px;
  white-space: normal !important;
}

.icmp-cell {
  min-width: 105px;
  font-weight: 800;
  color: #eaf2fb;
}

.port-table {
  min-width: 1580px;
}


.mini-series-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(220px, 290px));
  gap: 12px;
  min-width: 0;
}

.mini-series-card {
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 16px;
  padding: 10px 12px 10px;
  min-width: 0;
  background: linear-gradient(180deg, rgba(8, 16, 26, 0.90), rgba(10, 20, 30, 0.68));
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.03);
}

.mini-series-top {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 10px;
  margin-bottom: 8px;
}

.mini-series-kicker {
  color: var(--muted);
  text-transform: uppercase;
  letter-spacing: 0.10em;
  font-size: 10px;
  margin-bottom: 2px;
}

.mini-series-title {
  color: var(--text);
  font-size: 13px;
  font-weight: 700;
}

.mini-series-value {
  color: #ffffff;
  font-size: 21px;
  font-weight: 800;
  white-space: nowrap;
  line-height: 1.15;
  text-align: right;
}

.mini-series-svg {
  width: 100%;
  height: 56px;
  display: block;
  overflow: visible;
}

@media (max-width: 1280px) {
  .dash-header {
    align-items: flex-start;
    flex-direction: column;
  }

  .header-actions {
    width: 100%;
  }

  .mini-series-grid {
    width: 100%;
    grid-template-columns: repeat(2, minmax(180px, 1fr));
  }
}

@media (max-width: 760px) {
  .mini-series-grid {
    grid-template-columns: 1fr;
  }
}

options.onRender:
(function () {
  const hg = typeof htmlGraphics !== 'undefined' ? htmlGraphics : {};
  const props = hg.customProperties || (typeof customProperties !== 'undefined' ? customProperties : {}) || {};
  const panelData = hg.data || (typeof data !== 'undefined' ? data : { series: [] });

  const root = htmlNode.querySelector('#sw1-root');
  const rowsEl = htmlNode.querySelector('#switchRows');
  const emptyEl = htmlNode.querySelector('#emptyState');
  const rowCountEl = htmlNode.querySelector('#rowCount');
  const searchEl = htmlNode.querySelector('#tableSearch');
  const titleEl = htmlNode.querySelector('#dashTitle');
  const subtitleEl = htmlNode.querySelector('#dashSubtitle');
  const miniRxValueEl = htmlNode.querySelector('#miniRxValue');
  const miniTxValueEl = htmlNode.querySelector('#miniTxValue');
  const miniRxSvgEl = htmlNode.querySelector('#miniRxSvg');
  const miniTxSvgEl = htmlNode.querySelector('#miniTxSvg');
  const updatedEl = htmlNode.querySelector('#lastUpdated');
  const debugEl = htmlNode.querySelector('#debugItems');
  const kpiTotalEl = htmlNode.querySelector('#kpiTotal');
  const kpiOnlineEl = htmlNode.querySelector('#kpiOnline');
  const kpiOfflineEl = htmlNode.querySelector('#kpiOffline');
  const kpiPort1ProblemsEl = htmlNode.querySelector('#kpiPort1Problems');
  const kpiTotalTrafficEl = htmlNode.querySelector('#kpiTotalTraffic');

  if (!root || !rowsEl || !emptyEl) return;

  const cfg = Object.assign({
    title: 'Switches - Status e Porta Monitorada',
    subtitle: 'Status ICMP, latência/perda ICMP, tráfego total RX/TX e métricas da porta monitorada',
    monitoredPort: '1',
    monitoredPortByHost: {},
    fallbackSpeedMbps: 1000,
    miniSeriesBucketMs: 60000,
    usageWarnPct: 70,
    usageCriticalPct: 90,
    errorWarnCount: 1,
    discardWarnCount: 1
  }, props);

  const state = root.__switchTableState || {
    sortKey: 'host',
    sortDir: 'asc',
    filter: 'all',
    search: ''
  };
  root.__switchTableState = state;

  const safeText = (value) => String(value ?? '').replace(/[&<>"']/g, (char) => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  }[char]));

  const normalizeText = (text) => String(text || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();

  const vectorToArray = (values) => {
    if (!values) return [];
    if (Array.isArray(values)) return values;
    if (typeof values.toArray === 'function') return values.toArray();
    if (typeof values.length === 'number') {
      const arr = [];
      for (let i = 0; i < values.length; i += 1) {
        arr.push(typeof values.get === 'function' ? values.get(i) : values[i]);
      }
      return arr;
    }
    return [];
  };

  const lastNonEmpty = (field) => {
    const arr = vectorToArray(field.values);
    for (let i = arr.length - 1; i >= 0; i -= 1) {
      const value = arr[i];
      if (value !== null && value !== undefined && value !== '') return value;
    }
    const calc = field.state && field.state.calcs;
    if (calc) {
      const candidates = [calc.lastNotNull, calc.last, calc.mean, calc.max];
      for (const candidate of candidates) {
        if (candidate !== null && candidate !== undefined && candidate !== '') return candidate;
      }
    }
    return null;
  };

  const getTimeField = (series) => (series.fields || []).find((f) => f.type === 'time' || /time/i.test(f.name || ''));

  const lastTime = (series) => {
    const timeField = getTimeField(series);
    if (!timeField) return null;
    const arr = vectorToArray(timeField.values);
    for (let i = arr.length - 1; i >= 0; i -= 1) {
      const ts = Number(arr[i]);
      if (Number.isFinite(ts)) return ts;
    }
    return null;
  };

  const addSeriesToHistory = (bucketMap, timeField, valueField) => {
    if (!timeField || !valueField) return;
    const times = vectorToArray(timeField.values);
    const values = vectorToArray(valueField.values);
    const len = Math.min(times.length, values.length);

    for (let i = 0; i < len; i += 1) {
      const ts = Number(times[i]);
      const val = metricValueToNumber(values[i]);
      if (!Number.isFinite(ts) || !Number.isFinite(val)) continue;
      bucketMap.set(ts, (bucketMap.get(ts) || 0) + val);
    }
  };

  const historyToPoints = (bucketMap) => Array.from(bucketMap.entries())
    .map(([ts, value]) => ({ ts: Number(ts), value: Number(value) }))
    .filter((p) => Number.isFinite(p.ts) && Number.isFinite(p.value))
    .sort((a, b) => a.ts - b.ts);

  const downsamplePoints = (points, maxPoints) => {
    if (!Array.isArray(points) || points.length <= maxPoints) return points || [];
    const step = (points.length - 1) / (maxPoints - 1);
    const sampled = [];
    for (let i = 0; i < maxPoints; i += 1) {
      sampled.push(points[Math.round(i * step)]);
    }
    return sampled;
  };

  const renderSparkline = (svgEl, points, color) => {
    if (!svgEl) return;

    const width = 220;
    const height = 56;
    const padX = 2;
    const padY = 4;

    if (!points || !points.length) {
      svgEl.innerHTML = '<path d="M 2 28 L 218 28" fill="none" stroke="rgba(148,163,184,0.35)" stroke-width="2" stroke-dasharray="4 4"></path>';
      return;
    }

    const values = points.map((p) => p.value);
    let minV = Math.min.apply(null, values);
    let maxV = Math.max.apply(null, values);

    if (minV === maxV) {
      minV -= 1;
      maxV += 1;
    }

    const usableW = width - (padX * 2);
    const usableH = height - (padY * 2);

    const coords = points.map((p, i) => {
      const x = padX + ((usableW * i) / Math.max(1, points.length - 1));
      const normalized = (p.value - minV) / Math.max(1e-9, (maxV - minV));
      const y = height - padY - (normalized * usableH);
      return [x, y];
    });

    const linePath = coords.map((c, i) => (i === 0 ? 'M ' : ' L ') + c[0].toFixed(2) + ' ' + c[1].toFixed(2)).join('');
    const areaPath = linePath + ' L ' + coords[coords.length - 1][0].toFixed(2) + ' ' + (height - padY).toFixed(2) + ' L ' + coords[0][0].toFixed(2) + ' ' + (height - padY).toFixed(2) + ' Z';
    const last = coords[coords.length - 1];

    svgEl.innerHTML = [
      '<defs>',
      '  <linearGradient id="grad-' + color.replace(/[^a-z0-9]/gi, '') + '" x1="0" y1="0" x2="0" y2="1">',
      '    <stop offset="0%" stop-color="' + color + '" stop-opacity="0.30"></stop>',
      '    <stop offset="100%" stop-color="' + color + '" stop-opacity="0.02"></stop>',
      '  </linearGradient>',
      '</defs>',
      '<path d="' + areaPath + '" fill="url(#grad-' + color.replace(/[^a-z0-9]/gi, '') + ')"></path>',
      '<path d="' + linePath + '" fill="none" stroke="' + color + '" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"></path>',
      '<circle cx="' + last[0].toFixed(2) + '" cy="' + last[1].toFixed(2) + '" r="3.3" fill="' + color + '" stroke="#09111a" stroke-width="1.3"></circle>'
    ].join('');
  };

  const metricValueToNumber = (value) => {
    if (value === null || value === undefined || value === '') return null;
    if (typeof value === 'number') return Number.isFinite(value) ? value : null;

    const raw = String(value).trim();
    if (!raw) return null;

    const normalized = raw.replace(/\s+/g, ' ').replace(',', '.').toLowerCase();

    const bps = normalized.match(/^(-?\d+(?:\.\d+)?)\s*([kmgt]?)(?:bit\/s|bits\/s|bps|b\/s|ps|p\/s)?$/i);
    if (bps) {
      const num = Number(bps[1]);
      if (!Number.isFinite(num)) return null;
      const unit = (bps[2] || '').toLowerCase();
      const multiplier = unit === 't' ? 1e12
        : unit === 'g' ? 1e9
        : unit === 'm' ? 1e6
        : unit === 'k' ? 1e3
        : 1;
      return num * multiplier;
    }

    const n = Number(raw);
    return Number.isFinite(n) ? n : null;
  };

  const durationToMs = (value) => {
    if (value === null || value === undefined || value === '') return null;
    if (typeof value === 'number') {
      if (!Number.isFinite(value)) return null;
      return value < 10 ? value * 1000 : value;
    }

    const raw = String(value).trim().replace(',', '.').toLowerCase();
    const m = raw.match(/^(-?\d+(?:\.\d+)?)\s*(µs|us|micro?s|ms|msec|s|sec|seg|seconds?)?$/i);
    if (!m) return metricValueToNumber(value);

    const n = Number(m[1]);
    if (!Number.isFinite(n)) return null;

    const unit = m[2] || '';
    if (unit === 'µs' || unit === 'us' || /micro/.test(unit)) return n / 1000;
    if (unit === 'ms' || unit === 'msec') return n;
    if (unit === 's' || unit === 'sec' || unit === 'seg' || /second/.test(unit)) return n * 1000;

    return n < 10 ? n * 1000 : n;
  };

  const getDisplayName = (series, field) => {
    const names = [
      field?.config?.displayNameFromDS,
      field?.config?.displayName,
      series?.name,
      field?.name
    ].filter(Boolean);

    let name = names.find((n) => /Interface\s+[^:]+:/i.test(String(n)));
    if (!name) name = names.find((n) => /icmp|ping|bits received|bits sent|operational status|speed|packets with errors|packets discarded|interface type/i.test(String(n)));
    if (!name) name = names[0] || '';

    return String(name);
  };

  const getFullSearchText = (series, field, displayName) => {
    return [
      displayName,
      series?.name,
      field?.name,
      field?.config?.displayNameFromDS,
      field?.config?.displayName,
      field?.labels ? JSON.stringify(field.labels) : '',
      series?.labels ? JSON.stringify(series.labels) : ''
    ].filter(Boolean).join(' ');
  };

  const cleanHostName = (host) => {
    let h = String(host || '').trim();
    h = h.replace(/^["']|["']$/g, '');
    h = h.replace(/\s+/g, ' ');
    return h || 'Switch';
  };

  const hostFrom = (series, field, displayName, fullText) => {
    const labelObjects = [field?.labels || {}, series?.labels || {}];
    const labelKeys = ['host', 'hostname', 'host_name', 'hostName', 'zabbix_host', 'zbx_host'];

    for (const labels of labelObjects) {
      for (const key of labelKeys) {
        if (labels && labels[key]) return cleanHostName(labels[key]);
      }
    }

    const candidates = [
      displayName,
      series?.name,
      field?.config?.displayNameFromDS,
      field?.config?.displayName,
      fullText
    ].filter(Boolean).map(String);

    for (const candidate of candidates) {
      let m = candidate.match(/^([^:]+):\s*Interface\s+/i);
      if (m) return cleanHostName(m[1]);

      m = candidate.match(/^([^:]+):\s*(?:ICMP|icmp|Ping|ping|Disponibilidade|disponibilidade)/i);
      if (m) return cleanHostName(m[1]);
    }

    const jsonHost = String(fullText || '').match(/"host(?:name|_name|Name)?"\s*:\s*"([^"]+)"/i);
    if (jsonHost) return cleanHostName(jsonHost[1]);

    return 'Switch';
  };

  const metricFrom = (text) => {
    const t = normalizeText(text);

    // ICMP do Zabbix.
    if (/(^|\b)(icmp response time|icmppingsec|icmp ping time|icmp.*tempo|tempo.*icmp|latencia icmp|icmp latency)(\b|$)/.test(t)
        && !/loss|perda/.test(t)) {
      return 'icmpLatency';
    }

    if (/(^|\b)(icmp loss|icmppingloss|icmp ping loss|icmp.*perda|perda.*icmp|packet loss|ping loss)(\b|$)/.test(t)) {
      return 'icmpLoss';
    }

    if (/(^|\b)(icmp ping|icmpping|ping status|status ping|ping availability|disponibilidade icmp)(\b|$)/.test(t)
        && !/response|resposta|time|tempo|loss|perda|latency|latencia|icmppingsec|icmppingloss/.test(t)) {
      return 'switchStatus';
    }

    // Métricas específicas primeiro.
    // Isso evita que "Interface g1(...): Inbound packets with errors" seja classificado
    // incorretamente como bitsReceived quando o fullText também contém algum "Bits received".
    if (/inbound packets with errors|inbound error|in errors|ifinerrors|ifinerror|inerrors|inerror|inerros|inerro|rx errors|errors rx|receive errors|received errors|rx error packets|erros rx|erros de rx|erros entrada|erros in|entrada.*erro|crc errors rx|crc.*rx|rx.*crc/.test(t)) return 'inErrors';
    if (/outbound packets with errors|outbound error|out errors|ifouterrors|ifouterror|outerrors|outerror|outerros|outerro|tx errors|errors tx|transmit errors|transmitted errors|tx error packets|erros tx|erros de tx|erros saida|erros out|saida.*erro|crc errors tx|crc.*tx|tx.*crc/.test(t)) return 'outErrors';

    if (/inbound packets discarded|inbound discard|in discards|ifindiscards|ifindiscard|indiscards|indiscard|rx discards|discarded rx|receive discards|received discards|rx dropped|drop.*rx|descartes in|descartes rx|entrada.*descart/.test(t)) return 'inDiscards';
    if (/outbound packets discarded|outbound discard|out discards|ifoutdiscards|ifoutdiscard|outdiscards|outdiscard|tx discards|discarded tx|transmit discards|transmitted discards|tx dropped|drop.*tx|descartes out|descartes tx|saida.*descart/.test(t)) return 'outDiscards';

    if (/operational status|ifoperstatus|status operacional|net\.if\.status/.test(t)) return 'operStatus';
    if (/interface type|iftype|tipo.*interface/.test(t)) return 'interfaceType';
    if (/speed|ifspeed|ifhighspeed|velocidade/.test(t)) return 'speed';

    // Tráfego por último, porque é mais genérico.
    if (/bits received|incoming traffic|inbound traffic|download|entrada|net\.if\.in|ifhcin|ifinoctets/.test(t)) return 'bitsReceived';
    if (/bits sent|outgoing traffic|outbound traffic|upload|saida|net\.if\.out|ifhcout|ifoutoctets/.test(t)) return 'bitsSent';

    return null;
  };

  const cleanPortName = (value) => {
    let p = String(value || '').trim();
    p = p.replace(/^["']|["']$/g, '');
    p = p.replace(/\s+/g, ' ');
    p = p.replace(/^(port|porta)\s+/i, '');
    p = p.replace(/\(\)\s*$/g, '');
    p = p.replace(/^crc\s*errors?\s*(rx|tx)?\s*(on\s*)?/i, '');
    p = p.replace(/^(?:if)?in(?:errors?|erros?|discards?)?/i, '');
    p = p.replace(/^(?:if)?out(?:errors?|erros?|discards?)?/i, '');
    p = p.replace(/^if(In|Out|HC|Oper|High|Type|Speed|Errors?|Discards?)/i, '');
    p = p.replace(/^tErrors/i, '');
    p = p.trim();
    return p || 'Interface';
  };

  const normalizePortKey = (value) => {
    let p = normalizeText(cleanPortName(value));
    p = p.replace(/\(.*?\)/g, '');
    p = p.replace(/^(fastethernet|gigabitethernet|tengigabitethernet|ethernet|eth|fa|gi|te|ge|g|xg)\s*/i, '');
    p = p.replace(/[^a-z0-9\/]+/g, '');

    if (/^trk/.test(p)) return p;

    const nums = p.match(/\d+/g);
    if (nums && nums.length) return String(Number(nums[nums.length - 1]));

    return p || 'unknown';
  };

  const getMonitoredPortForHost = (host) => {
    const defaultPort = String(cfg.monitoredPort || '1');
    const map = cfg.monitoredPortByHost || {};

    const hostName = String(host || '').trim();
    const normalizedHost = normalizeText(hostName);

    for (const [hostPattern, port] of Object.entries(map)) {
      const pattern = String(hostPattern || '').trim();
      if (!pattern) continue;

      // Match exato, ignorando maiúsculas/minúsculas e acentos.
      if (normalizeText(pattern) === normalizedHost) {
        return String(port);
      }

      // Match por regex. Ex.: "/DELL PowerConnect/" => "2".
      if (pattern.startsWith('/') && pattern.endsWith('/')) {
        try {
          const regex = new RegExp(pattern.slice(1, -1), 'i');
          if (regex.test(hostName)) {
            return String(port);
          }
        } catch (error) {
          // Regex inválido: ignora e segue para a próxima regra.
        }
      }

      // Match parcial simples. Ex.: "DELL PowerConnect" casa com "Switch DELL PowerConnect 2848".
      if (!pattern.startsWith('/') && !pattern.endsWith('/') && normalizedHost.includes(normalizeText(pattern))) {
        return String(port);
      }
    }

    return defaultPort;
  };

  const isMonitoredPort = (portKey, portLabel, wantedPort) => {
    const monitoredPortKey = normalizePortKey(wantedPort || cfg.monitoredPort || '1');

    if (String(portKey) === String(monitoredPortKey)) return true;
    return normalizePortKey(portLabel) === String(monitoredPortKey);
  };

  const portFrom = (displayName, fullText) => {
    const preferred = String(displayName || '');
    const full = String(fullText || '');

    let m;

    m = preferred.match(/Interface\s+([^:]+):/i);
    if (m) return cleanPortName(m[1]);

    m = full.match(/Interface\s+([^:]+):/i);
    if (m) return cleanPortName(m[1]);

    m = preferred.match(/\b(?:if)?in(?:errors?|erros?)\s*((?:Fa|Gi|Ge|Te|Eth|Ethernet|FastEthernet|GigabitEthernet|TenGigabitEthernet|g|xg)?\s*\d+(?:\/\d+)*)\b/i);
    if (m) return cleanPortName(m[1]);

    m = full.match(/\b(?:if)?in(?:errors?|erros?)\s*((?:Fa|Gi|Ge|Te|Eth|Ethernet|FastEthernet|GigabitEthernet|TenGigabitEthernet|g|xg)?\s*\d+(?:\/\d+)*)\b/i);
    if (m) return cleanPortName(m[1]);

    m = preferred.match(/\b(?:if)?out(?:errors?|erros?)\s*((?:Fa|Gi|Ge|Te|Eth|Ethernet|FastEthernet|GigabitEthernet|TenGigabitEthernet|g|xg)?\s*\d+(?:\/\d+)*)\b/i);
    if (m) return cleanPortName(m[1]);

    m = full.match(/\b(?:if)?out(?:errors?|erros?)\s*((?:Fa|Gi|Ge|Te|Eth|Ethernet|FastEthernet|GigabitEthernet|TenGigabitEthernet|g|xg)?\s*\d+(?:\/\d+)*)\b/i);
    if (m) return cleanPortName(m[1]);

    m = preferred.match(/\b(?:if)?in(?:discards?)\s*((?:Fa|Gi|Ge|Te|Eth|Ethernet|FastEthernet|GigabitEthernet|TenGigabitEthernet|g|xg)?\s*\d+(?:\/\d+)*)\b/i);
    if (m) return cleanPortName(m[1]);

    m = full.match(/\b(?:if)?in(?:discards?)\s*((?:Fa|Gi|Ge|Te|Eth|Ethernet|FastEthernet|GigabitEthernet|TenGigabitEthernet|g|xg)?\s*\d+(?:\/\d+)*)\b/i);
    if (m) return cleanPortName(m[1]);

    m = preferred.match(/\b(?:if)?out(?:discards?)\s*((?:Fa|Gi|Ge|Te|Eth|Ethernet|FastEthernet|GigabitEthernet|TenGigabitEthernet|g|xg)?\s*\d+(?:\/\d+)*)\b/i);
    if (m) return cleanPortName(m[1]);

    m = full.match(/\b(?:if)?out(?:discards?)\s*((?:Fa|Gi|Ge|Te|Eth|Ethernet|FastEthernet|GigabitEthernet|TenGigabitEthernet|g|xg)?\s*\d+(?:\/\d+)*)\b/i);
    if (m) return cleanPortName(m[1]);

    m = preferred.match(/\bon\s+port\s+([A-Za-z0-9\/\.\-_]+)\b/i);
    if (m) return cleanPortName(m[1]);

    m = full.match(/\bon\s+port\s+([A-Za-z0-9\/\.\-_]+)\b/i);
    if (m) return cleanPortName(m[1]);

    m = preferred.match(/(?:^|[\s:\[,])((?:TRK|Trk|Gi|Ge|GigabitEthernet|Te|TenGigabitEthernet|Eth|Ethernet|Fa|FastEthernet|Porta?|Port|g|xg)\s*[-\w\/\.\(\)]+)/i);
    if (m) return cleanPortName(m[1]);

    m = full.match(/(?:^|[\s:\[,])((?:TRK|Trk|Gi|Ge|GigabitEthernet|Te|TenGigabitEthernet|Eth|Ethernet|Fa|FastEthernet|Porta?|Port|g|xg)\s*[-\w\/\.\(\)]+)/i);
    if (m) return cleanPortName(m[1]);

    return null;
  };

  const statusInfo = (value) => {
    if (value === null || value === undefined || value === '') {
      return { label: 'Sem dado', className: 'unknown', rank: 2 };
    }

    const n = metricValueToNumber(value);
    if (Number.isFinite(n)) {
      if (n === 1) return { label: 'UP', className: 'up', rank: 0 };
      if (n === 2) return { label: 'DOWN', className: 'down', rank: 4 };
      if (n === 3) return { label: 'Testing', className: 'warn', rank: 1 };
      if (n === 4) return { label: 'Unknown', className: 'unknown', rank: 2 };
      if (n === 5) return { label: 'Dormant', className: 'warn', rank: 1 };
      if (n === 6) return { label: 'Not present', className: 'down', rank: 4 };
      if (n === 7) return { label: 'Lower layer down', className: 'down', rank: 4 };
    }

    const text = String(value).toLowerCase();
    if (/^1$|\bup\b|online|ok|ativo|established/.test(text)) return { label: 'UP', className: 'up', rank: 0 };
    if (/^2$|\bdown\b|offline|falha|inativo/.test(text)) return { label: 'DOWN', className: 'down', rank: 4 };
    if (/^3$|testing/.test(text)) return { label: 'Testing', className: 'warn', rank: 1 };
    if (/^4$|unknown/.test(text)) return { label: 'Unknown', className: 'unknown', rank: 2 };
    if (/^5$|dormant/.test(text)) return { label: 'Dormant', className: 'warn', rank: 1 };
    if (/^6$|not\s*present/.test(text)) return { label: 'Not present', className: 'down', rank: 4 };
    if (/^7$|lower\s*layer\s*down/.test(text)) return { label: 'Lower layer down', className: 'down', rank: 4 };
    return { label: String(value), className: 'unknown', rank: 2 };
  };

  const switchIcmpStatusInfo = (value) => {
    if (value === null || value === undefined || value === '') {
      return { label: 'Sem dado', className: 'unknown', rank: 2 };
    }

    const n = metricValueToNumber(value);
    if (Number.isFinite(n)) {
      if (n >= 1) return { label: 'ONLINE', className: 'up', rank: 0 };
      if (n === 0) return { label: 'OFFLINE', className: 'down', rank: 4 };
    }

    const text = String(value).toLowerCase();
    if (/online|up|ok|ativo|available|disponivel|true/.test(text)) return { label: 'ONLINE', className: 'up', rank: 0 };
    if (/offline|down|falha|inativo|unavailable|indisponivel|false/.test(text)) return { label: 'OFFLINE', className: 'down', rank: 4 };

    return { label: String(value), className: 'unknown', rank: 2 };
  };

  const formatBps = (value) => {
    const n = metricValueToNumber(value);
    if (!Number.isFinite(n)) return '—';
    const abs = Math.abs(n);
    if (abs >= 1000000000) return (n / 1000000000).toFixed(2) + ' Gbps';
    if (abs >= 1000000) return (n / 1000000).toFixed(2) + ' Mbps';
    if (abs >= 1000) return (n / 1000).toFixed(1) + ' Kbps';
    return n.toFixed(0) + ' bps';
  };

  const formatCounter = (value) => {
    const n = metricValueToNumber(value);
    if (!Number.isFinite(n)) return '—';
    if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';
    if (n >= 1000) return (n / 1000).toFixed(1) + 'K';
    return String(Math.round(n));
  };

  const formatLatency = (value) => {
    const ms = durationToMs(value);
    if (!Number.isFinite(ms)) return '—';
    if (ms < 1) return (ms * 1000).toFixed(0) + ' µs';
    if (ms < 1000) return ms.toFixed(ms >= 10 ? 0 : 1) + ' ms';
    return (ms / 1000).toFixed(2) + ' s';
  };

  const percentValueToNumber = (value) => {
    if (value === null || value === undefined || value === '') return null;
    if (typeof value === 'number') return Number.isFinite(value) ? value : null;

    const raw = String(value).trim().replace(',', '.').toLowerCase();
    const m = raw.match(/^(-?\d+(?:\.\d+)?)\s*%?$/);
    if (!m) return metricValueToNumber(value);

    const n = Number(m[1]);
    return Number.isFinite(n) ? n : null;
  };

  const formatPercent = (value) => {
    const n = percentValueToNumber(value);
    if (!Number.isFinite(n)) return '—';
    return n.toFixed(n >= 10 ? 0 : 1) + '%';
  };

  const formatIcmp = (latency, loss) => {
    const latencyMs = durationToMs(latency);
    if (Number.isFinite(latencyMs)) return formatLatency(latency);

    const lossPct = percentValueToNumber(loss);
    if (Number.isFinite(lossPct)) return formatPercent(loss) + ' loss';

    return '—';
  };

  const setMetric = (target, metric, valueRaw, ts, preferMax) => {
    if (!target.metricUpdatedAt) target.metricUpdatedAt = {};
    const parsed = metricValueToNumber(valueRaw);
    const value = parsed !== null ? parsed : valueRaw;

    const currentTs = target.metricUpdatedAt[metric] || 0;
    const currentValue = metricValueToNumber(target[metric]);
    const incomingValue = metricValueToNumber(value);

    let shouldReplace = target[metric] === null || target[metric] === undefined || ts > currentTs;

    if (!shouldReplace && ts === currentTs && preferMax && Number.isFinite(incomingValue) && Number.isFinite(currentValue)) {
      shouldReplace = Math.abs(incomingValue) > Math.abs(currentValue);
    }

    if (shouldReplace) {
      target[metric] = value;
      target.metricUpdatedAt[metric] = ts;
    }
  };

  const devices = new Map();
  const totalRxHistory = new Map();
  const totalTxHistory = new Map();
  const calcRxHistory = new Map();
  const calcTxHistory = new Map();
  const debugLines = [];

  const getDevice = (host) => {
    const key = host || 'Switch';
    if (!devices.has(key)) {
      devices.set(key, {
        host: key,
        switchStatus: null,
        icmpLatency: null,
        icmpLoss: null,
        updatedAt: null,
        metricUpdatedAt: {},
        ports: new Map(),
        raw: []
      });
    }
    return devices.get(key);
  };

  const getPort = (device, portLabel) => {
    const key = normalizePortKey(portLabel);
    if (!device.ports.has(key)) {
      device.ports.set(key, {
        key,
        label: cleanPortName(portLabel),
        bitsReceived: null,
        bitsSent: null,
        inErrors: null,
        outErrors: null,
        inDiscards: null,
        outDiscards: null,
        operStatus: null,
        speed: null,
        updatedAt: null,
        metricUpdatedAt: {},
        raw: []
      });
    }

    const port = device.ports.get(key);
    const cleanLabel = cleanPortName(portLabel);
    if (cleanLabel && cleanLabel !== 'Interface' && port.label === key) {
      port.label = cleanLabel;
    }
    return port;
  };

  (panelData.series || []).forEach((series) => {
    (series.fields || []).forEach((field) => {
      if (field.type === 'time' || /time/i.test(field.name || '')) return;

      const valueRaw = lastNonEmpty(field);
      if (valueRaw === null) return;

      const displayName = getDisplayName(series, field);
      const fullText = getFullSearchText(series, field, displayName);
      const normalizedFullText = normalizeText(fullText);
      const timeField = getTimeField(series);

      // Itens calculados do Zabbix: Traffic LAN.
      // A query B deve retornar os itens:
      // - RX - Tráfego total dos switchs
      // - TX - Tráfego total dos switchs
      if (/rx\s*-\s*trafego total dos switchs|rx\s*-\s*trafego total dos switches|rx.*trafego total/.test(normalizedFullText)) {
        addSeriesToHistory(calcRxHistory, timeField, field);
        debugLines.push('[OK TOTAL RX ZABBIX] ' + displayName + ' = ' + valueRaw);
        return;
      }

      if (/tx\s*-\s*trafego total dos switchs|tx\s*-\s*trafego total dos switches|tx.*trafego total/.test(normalizedFullText)) {
        addSeriesToHistory(calcTxHistory, timeField, field);
        debugLines.push('[OK TOTAL TX ZABBIX] ' + displayName + ' = ' + valueRaw);
        return;
      }

      const metric = metricFrom(displayName) || metricFrom(fullText);

      if (!metric) {
        debugLines.push('[IGNORADO] ' + displayName);
        return;
      }

      // Fallback: se a query B não trouxer os itens calculados,
      // os mini gráficos ainda usam a soma das séries de tráfego da query A.
      if (metric === 'bitsReceived') addSeriesToHistory(totalRxHistory, timeField, field);
      if (metric === 'bitsSent') addSeriesToHistory(totalTxHistory, timeField, field);

      const host = hostFrom(series, field, displayName, fullText);
      const device = getDevice(host);
      const ts = lastTime(series) || 0;
      device.updatedAt = Math.max(device.updatedAt || 0, ts);

      if (metric === 'switchStatus' || metric === 'icmpLatency' || metric === 'icmpLoss') {
        setMetric(device, metric, valueRaw, ts, false);
        debugLines.push('[OK SWITCH] ' + host + ' | ' + metric + ' | ' + displayName + ' = ' + valueRaw);
        return;
      }

      const portLabel = portFrom(displayName, fullText);
      if (!portLabel) {
        debugLines.push('[SEM PORTA] ' + host + ' | ' + displayName + ' => ' + metric);
        return;
      }

      const port = getPort(device, portLabel);
      const preferMax = metric === 'bitsReceived' || metric === 'bitsSent' || metric === 'inErrors' || metric === 'outErrors' || metric === 'inDiscards' || metric === 'outDiscards';

      setMetric(port, metric, valueRaw, ts, preferMax);
      port.updatedAt = Math.max(port.updatedAt || 0, ts);
      port.raw.push({ metric, text: displayName, value: valueRaw });
      device.raw.push({ port: port.label, metric, text: displayName, value: valueRaw });

      debugLines.push('[OK PORTA] ' + host + ' | ' + port.label + ' [' + port.key + '] | ' + metric + ' | ' + displayName + ' = ' + valueRaw);
    });
  });

  const rows = Array.from(devices.values()).map((device) => {
    let totalRx = 0;
    let totalTx = 0;

    device.ports.forEach((port) => {
      const rx = metricValueToNumber(port.bitsReceived);
      const tx = metricValueToNumber(port.bitsSent);
      if (Number.isFinite(rx)) totalRx += rx;
      if (Number.isFinite(tx)) totalTx += tx;
    });

    const wantedPort = getMonitoredPortForHost(device.host);

    const port1 = Array.from(device.ports.values())
      .find((port) => isMonitoredPort(port.key, port.label, wantedPort)) || null;

    const switchStatus = switchIcmpStatusInfo(device.switchStatus);
    const portStatus = port1 ? statusInfo(port1.operStatus) : { label: 'Sem dado', className: 'unknown', rank: 2 };

    const inErrors = port1 ? (metricValueToNumber(port1.inErrors) || 0) : 0;
    const outErrors = port1 ? (metricValueToNumber(port1.outErrors) || 0) : 0;
    const inDiscards = port1 ? (metricValueToNumber(port1.inDiscards) || 0) : 0;
    const outDiscards = port1 ? (metricValueToNumber(port1.outDiscards) || 0) : 0;

    const hasErrors = inErrors > 0 || outErrors > 0;
    const hasDiscards = inDiscards > 0 || outDiscards > 0;
    const portProblem = !port1 || portStatus.className !== 'up' || hasErrors || hasDiscards;

    return {
      host: device.host,
      wantedPort,
      switchStatus,
      icmpLatency: device.icmpLatency,
      icmpLoss: device.icmpLoss,
      totalRx,
      totalTx,
      port1Label: port1 ? port1.label : 'Porta ' + wantedPort,
      portStatus,
      port1Download: port1 ? port1.bitsReceived : null,
      port1Upload: port1 ? port1.bitsSent : null,
      inErrors: port1 ? port1.inErrors : null,
      outErrors: port1 ? port1.outErrors : null,
      inDiscards: port1 ? port1.inDiscards : null,
      outDiscards: port1 ? port1.outDiscards : null,
      updatedAt: Math.max(device.updatedAt || 0, port1?.updatedAt || 0),
      hasErrors,
      hasDiscards,
      portProblem,
      raw: device.raw
    };
  }).sort((a, b) => String(a.host).localeCompare(String(b.host), 'pt-BR'));

  if (debugEl) {
    const header = [
      'Total de séries recebidas: ' + ((panelData.series || []).length),
      'Switches identificados: ' + rows.length,
      'Porta padrão: ' + (cfg.monitoredPort || '1'),
      'Mapa por host: ' + JSON.stringify(cfg.monitoredPortByHost || {}),
      'Query do painel: Item = /.*/',
      ''
    ];
    debugEl.textContent = header.concat(debugLines.slice(0, 500)).join('\n');
  }

  const onlineCount = rows.filter((r) => r.switchStatus.className === 'up').length;
  const offlineCount = rows.filter((r) => r.switchStatus.className === 'down').length;
  const port1ProblemCount = rows.filter((r) => r.portProblem).length;
  const totalTraffic = rows.reduce((sum, r) => sum + (metricValueToNumber(r.totalRx) || 0) + (metricValueToNumber(r.totalTx) || 0), 0);

  // Usa os itens calculados do Zabbix quando estiverem disponíveis.
  // Se a query B não retornar nada, usa a soma antiga feita pelo JavaScript como fallback.
  const rxSourceMap = calcRxHistory.size ? calcRxHistory : totalRxHistory;
  const txSourceMap = calcTxHistory.size ? calcTxHistory : totalTxHistory;

  const rxHistoryPoints = downsamplePoints(historyToPoints(rxSourceMap), 64);
  const txHistoryPoints = downsamplePoints(historyToPoints(txSourceMap), 64);

  const latestRxHistory = rxHistoryPoints.length
    ? rxHistoryPoints[rxHistoryPoints.length - 1].value
    : rows.reduce((sum, r) => sum + (metricValueToNumber(r.totalRx) || 0), 0);

  const latestTxHistory = txHistoryPoints.length
    ? txHistoryPoints[txHistoryPoints.length - 1].value
    : rows.reduce((sum, r) => sum + (metricValueToNumber(r.totalTx) || 0), 0);

  const trafficForKpi = latestRxHistory + latestTxHistory;

  if (titleEl) titleEl.textContent = cfg.title;
  if (subtitleEl) subtitleEl.textContent = cfg.subtitle;
  if (updatedEl) updatedEl.textContent = 'Atualizado: ' + new Date().toLocaleString('pt-BR');
  if (kpiTotalEl) kpiTotalEl.textContent = rows.length;
  if (kpiOnlineEl) kpiOnlineEl.textContent = onlineCount;
  if (kpiOfflineEl) kpiOfflineEl.textContent = offlineCount;
  if (kpiPort1ProblemsEl) kpiPort1ProblemsEl.textContent = port1ProblemCount;
  if (kpiTotalTrafficEl) kpiTotalTrafficEl.textContent = formatBps(trafficForKpi);

  if (miniRxValueEl) miniRxValueEl.textContent = formatBps(latestRxHistory);
  if (miniTxValueEl) miniTxValueEl.textContent = formatBps(latestTxHistory);

  renderSparkline(miniRxSvgEl, rxHistoryPoints, '#22c55e');
  renderSparkline(miniTxSvgEl, txHistoryPoints, '#a78bfa');

  function compareRows(a, b, key) {
    const dir = state.sortDir === 'desc' ? -1 : 1;
    const val = (row) => {
      if (key === 'host') return row.host;
      if (key === 'switchStatus') return row.switchStatus.rank;
      if (key === 'icmp') return durationToMs(row.icmpLatency) ?? percentValueToNumber(row.icmpLoss) ?? -1;
      if (key === 'totalRx') return row.totalRx ?? -1;
      if (key === 'totalTx') return row.totalTx ?? -1;
      if (key === 'port1') return row.port1Label || '';
      if (key === 'portStatus') return row.portStatus.rank;
      if (key === 'download') return metricValueToNumber(row.port1Download) ?? -1;
      if (key === 'upload') return metricValueToNumber(row.port1Upload) ?? -1;
      if (key === 'inErrors') return metricValueToNumber(row.inErrors) ?? -1;
      if (key === 'outErrors') return metricValueToNumber(row.outErrors) ?? -1;
      if (key === 'inDiscards') return metricValueToNumber(row.inDiscards) ?? -1;
      if (key === 'outDiscards') return metricValueToNumber(row.outDiscards) ?? -1;
      if (key === 'updatedAt') return row.updatedAt ?? 0;
      return row.host || '';
    };

    const av = val(a);
    const bv = val(b);
    if (typeof av === 'number' && typeof bv === 'number') {
      const numeric = (av - bv) * dir;
      if (numeric !== 0) return numeric;
      return String(a.host).localeCompare(String(b.host), 'pt-BR');
    }

    return String(av).localeCompare(String(bv), 'pt-BR') * dir;
  }

  const counterClass = (value, threshold) => {
    const n = metricValueToNumber(value);
    if (!Number.isFinite(n)) return 'unknown';
    return n >= Number(threshold) ? 'warn' : 'ok';
  };

  function renderTable() {
    const term = normalizeText(state.search || '');

    const filtered = rows
      .filter((row) => {
        if (state.filter === 'online' && row.switchStatus.className !== 'up') return false;
        if (state.filter === 'offline' && row.switchStatus.className !== 'down') return false;
        if (state.filter === 'portdown' && row.portStatus.className === 'up') return false;
        if (state.filter === 'errors' && !row.hasErrors) return false;
        if (state.filter === 'discards' && !row.hasDiscards) return false;
        if (state.filter === 'problems' && !(row.switchStatus.className === 'down' || row.portProblem)) return false;

        if (!term) return true;

        const haystack = normalizeText([
          row.host,
          row.switchStatus.label,
          formatIcmp(row.icmpLatency, row.icmpLoss),
          row.port1Label,
          row.portStatus.label,
          formatBps(row.totalRx),
          formatBps(row.totalTx),
          formatBps(row.port1Download),
          formatBps(row.port1Upload),
          formatCounter(row.inErrors),
          formatCounter(row.outErrors),
          formatCounter(row.inDiscards),
          formatCounter(row.outDiscards)
        ].join(' '));

        return haystack.includes(term);
      })
      .sort((a, b) => compareRows(a, b, state.sortKey));

    if (rowCountEl) rowCountEl.textContent = filtered.length + (filtered.length === 1 ? ' linha' : ' linhas');

    if (!filtered.length) {
      rowsEl.innerHTML = '';
      emptyEl.style.display = 'flex';
      return;
    }

    emptyEl.style.display = 'none';

    rowsEl.innerHTML = filtered.map((row) => {
      const age = row.updatedAt ? new Date(row.updatedAt).toLocaleString('pt-BR') : '—';
      const rawTitle = safeText(row.raw.map((r) => r.port + ' | ' + r.metric + ': ' + r.text + ' = ' + r.value).join('\n'));

      const inErrClass = counterClass(row.inErrors, cfg.errorWarnCount);
      const outErrClass = counterClass(row.outErrors, cfg.errorWarnCount);
      const inDiscClass = counterClass(row.inDiscards, cfg.discardWarnCount);
      const outDiscClass = counterClass(row.outDiscards, cfg.discardWarnCount);

      return `
        <tr title="${rawTitle}">
          <td class="host-cell-main">${safeText(row.host)}<span class="subtext">Switch</span></td>
          <td class="status-cell ${row.switchStatus.className}">${safeText(row.switchStatus.label)}</td>
          <td class="icmp-cell">${safeText(formatIcmp(row.icmpLatency, row.icmpLoss))}</td>
          <td class="traffic-cell">
            <div class="traffic-value"><strong>${safeText(formatBps(row.totalRx))}</strong><span>Total RX</span></div>
            <div class="meter"><i class="download" style="width:${Math.min(100, (row.totalRx / 1000000000) * 100)}%"></i></div>
          </td>
          <td class="traffic-cell">
            <div class="traffic-value"><strong>${safeText(formatBps(row.totalTx))}</strong><span>Total TX</span></div>
            <div class="meter"><i class="upload" style="width:${Math.min(100, (row.totalTx / 1000000000) * 100)}%"></i></div>
          </td>
          <td class="port-cell-main">${safeText(row.port1Label)}<span class="subtext">alvo: ${safeText(row.wantedPort)}</span></td>
          <td class="status-cell ${row.portStatus.className}">${safeText(row.portStatus.label)}</td>
          <td class="traffic-cell">
            <div class="traffic-value"><strong>${safeText(formatBps(row.port1Download))}</strong><span>P1 RX</span></div>
            <div class="meter"><i class="download" style="width:${Math.min(100, ((metricValueToNumber(row.port1Download) || 0) / 1000000000) * 100)}%"></i></div>
          </td>
          <td class="traffic-cell">
            <div class="traffic-value"><strong>${safeText(formatBps(row.port1Upload))}</strong><span>P1 TX</span></div>
            <div class="meter"><i class="upload" style="width:${Math.min(100, ((metricValueToNumber(row.port1Upload) || 0) / 1000000000) * 100)}%"></i></div>
          </td>
          <td class="counter-cell ${inErrClass}">${safeText(formatCounter(row.inErrors))}</td>
          <td class="counter-cell ${outErrClass}">${safeText(formatCounter(row.outErrors))}</td>
          <td class="counter-cell ${inDiscClass}">${safeText(formatCounter(row.inDiscards))}</td>
          <td class="counter-cell ${outDiscClass}">${safeText(formatCounter(row.outDiscards))}</td>
          <td>${safeText(age)}</td>
        </tr>`;
    }).join('');
  }

  if (!root.dataset.bound) {
    if (searchEl) {
      searchEl.addEventListener('input', (event) => {
        state.search = event.target.value || '';
        renderTable();
      });
    }

    htmlNode.querySelectorAll('.filter-chip').forEach((button) => {
      button.addEventListener('click', () => {
        state.filter = button.dataset.filter || 'all';
        htmlNode.querySelectorAll('.filter-chip').forEach((b) => b.classList.toggle('active', b === button));
        renderTable();
      });
    });

    htmlNode.querySelectorAll('th[data-sort]').forEach((th) => {
      th.addEventListener('click', () => {
        const key = th.dataset.sort || 'host';
        if (state.sortKey === key) state.sortDir = state.sortDir === 'asc' ? 'desc' : 'asc';
        else {
          state.sortKey = key;
          state.sortDir = key === 'host' ? 'asc' : 'desc';
        }
        renderTable();
      });
    });

    root.dataset.bound = '1';
  }

  if (searchEl && searchEl.value !== state.search) searchEl.value = state.search;
  htmlNode.querySelectorAll('.filter-chip').forEach((b) => b.classList.toggle('active', (b.dataset.filter || 'all') === state.filter));

  renderTable();
})();
